--  DDL for Trigger TRG_ALERT_REORDER_POINT
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE TRIGGER "SGF_ADMIN"."TRG_ALERT_REORDER_POINT" 
AFTER UPDATE OF AvailableStock ON DetailInventory
FOR EACH ROW
 WHEN (NEW.AvailableStock <= NEW.MinStock AND OLD.AvailableStock > OLD.MinStock) DECLARE
    v_exists NUMBER;
BEGIN
    -- Kiểm tra xem đã có thông báo chưa đọc chưa
    SELECT COUNT(*)
    INTO v_exists
    FROM Notification
    WHERE Type = 1 AND Status = 0 AND ProductID = :NEW.ProductID;

    IF v_exists = 0 THEN
        INSERT INTO Notification (EmployeeID, Title, ProductID, Message, Type, Status, CreatedDate)
        VALUES (
            2, -- ID của thủ kho (có thể thay đổi)
            'Cảnh báo tồn kho thấp',
            :NEW.ProductID,
            'Sản phẩm ID ' || :NEW.ProductID || ' chỉ còn ' || :NEW.AvailableStock || ' đơn vị.',
            1,
            0,
            SYSDATE
        );
    END IF;
END;

/
ALTER TRIGGER "SGF_ADMIN"."TRG_ALERT_REORDER_POINT" ENABLE;
