--  DDL for Trigger TRG_CHECK_COMBO_PRODUCT_STATUS
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE TRIGGER "SGF_ADMIN"."TRG_CHECK_COMBO_PRODUCT_STATUS" 
BEFORE INSERT OR UPDATE OF ProductID ON ComboDetail
FOR EACH ROW
DECLARE
    v_status NUMBER;
BEGIN
    SELECT ProductStatus INTO v_status
    FROM Product
    WHERE ProductID = :NEW.ProductID;

    IF v_status != 1 THEN
        RAISE_APPLICATION_ERROR(-20011,
            'Sản phẩm ID=' || :NEW.ProductID || ' đã ngừng kinh doanh, không thể thêm vào combo.');
    END IF;
END;

/
ALTER TRIGGER "SGF_ADMIN"."TRG_CHECK_COMBO_PRODUCT_STATUS" ENABLE;
--------------------------------------------------------
--  DDL for Trigger TRG_CHECK_DISCOUNT_CUSTOMER_TYPE
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE TRIGGER "SGF_ADMIN"."TRG_CHECK_DISCOUNT_CUSTOMER_TYPE" 
BEFORE INSERT OR UPDATE ON ListDiscount
FOR EACH ROW
DECLARE
    v_cust_type_id      NUMBER;
    v_disc_type_id      NUMBER;
    v_cust_spending     NUMBER;
    v_disc_spending     NUMBER;
    v_order_cust_id     NUMBER;
BEGIN
    -- Lấy CustomerID từ Order
    SELECT CustomerID INTO v_order_cust_id
    FROM Orders
    WHERE OrderID = :NEW.OrderID;

    -- Lấy CustomerTypeID của khách hàng
    SELECT CustomerTypeID INTO v_cust_type_id
    FROM Customer
    WHERE CustomerID = v_order_cust_id;

    -- Lấy CustomerTypeID của Discount
    SELECT CustomerTypeID INTO v_disc_type_id
    FROM Discount
    WHERE DiscountID = :NEW.DiscountID;

    -- Nếu Discount không yêu cầu loại khách hàng (NULL) thì ai cũng được dùng
    IF v_disc_type_id IS NULL THEN
        RETURN;
    END IF;

    -- Nếu Discount có yêu cầu loại khách hàng mà khách hàng không có loại (NULL) thì từ chối
    IF v_cust_type_id IS NULL THEN
        RAISE_APPLICATION_ERROR(-20030,
            'Khách hàng chưa được phân hạng, không thể sử dụng mã giảm giá có điều kiện.');
    END IF;

    -- Lấy SpendingLimit của hai loại để so sánh
    SELECT SpendingLimit INTO v_cust_spending
    FROM CustomerType
    WHERE CustomerTypeID = v_cust_type_id;

    SELECT SpendingLimit INTO v_disc_spending
    FROM CustomerType
    WHERE CustomerTypeID = v_disc_type_id;

    -- Khách chỉ được dùng nếu hạng của khách >= hạng yêu cầu của mã
    IF v_cust_spending < v_disc_spending THEN
        RAISE_APPLICATION_ERROR(-20031,
            'Khách hàng hạng ' || v_cust_type_id || 
            ' không đủ điều kiện sử dụng mã giảm giá yêu cầu hạng ' || v_disc_type_id || '.');
    END IF;

END;

/
ALTER TRIGGER "SGF_ADMIN"."TRG_CHECK_DISCOUNT_CUSTOMER_TYPE" ENABLE;
--------------------------------------------------------
--  DDL for Trigger TRG_CHECK_DUPLICATE_NOTIFICATION
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE TRIGGER "SGF_ADMIN"."TRG_CHECK_DUPLICATE_NOTIFICATION" 
BEFORE INSERT ON Notification
FOR EACH ROW
DECLARE
    v_count NUMBER;
BEGIN
    IF :NEW.Type = 1 AND :NEW.Status = 0 THEN
        SELECT COUNT(*)
        INTO v_count
        FROM Notification
        WHERE Type = 1 AND Status = 0 AND ProductID = :NEW.ProductID;

        IF v_count > 0 THEN
            RAISE_APPLICATION_ERROR(-20009,
                'Đã tồn tại thông báo thiếu hàng chưa đọc cho sản phẩm này.');
        END IF;
    END IF;
END;

/
ALTER TRIGGER "SGF_ADMIN"."TRG_CHECK_DUPLICATE_NOTIFICATION" ENABLE;
--------------------------------------------------------
--  DDL for Trigger TRG_CHECK_ORDER_HAS_ITEMS
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE TRIGGER "SGF_ADMIN"."TRG_CHECK_ORDER_HAS_ITEMS" 
BEFORE UPDATE OF OrderStatus ON Orders
FOR EACH ROW
 WHEN (NEW.OrderStatus IN (1, 2)) DECLARE
    v_count NUMBER;
BEGIN
    SELECT COUNT(*)
    INTO v_count
    FROM OrderDetail
    WHERE OrderID = :NEW.OrderID
      AND (ProductID IS NOT NULL OR ComboID IS NOT NULL);

    IF v_count = 0 THEN
        RAISE_APPLICATION_ERROR(-20014,
            'Đơn hàng phải có ít nhất một sản phẩm hoặc combo.');
    END IF;
END;

/
ALTER TRIGGER "SGF_ADMIN"."TRG_CHECK_ORDER_HAS_ITEMS" ENABLE;
--------------------------------------------------------
--  DDL for Trigger TRG_CHECK_ORDER_QUANTITY
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE TRIGGER "SGF_ADMIN"."TRG_CHECK_ORDER_QUANTITY" 
BEFORE INSERT OR UPDATE OF Quantity, ProductID ON OrderDetail
FOR EACH ROW
 WHEN (NEW.ProductID IS NOT NULL) DECLARE
    v_available    NUMBER;
    v_warehouse_id NUMBER;
    v_has_shipping NUMBER;
BEGIN
    -- Xác định có phải đơn online không
    SELECT CASE WHEN o.ShipCode IS NOT NULL OR o.ShipCompanyID IS NOT NULL THEN 1 ELSE 0 END
    INTO v_has_shipping
    FROM Orders o
    WHERE o.OrderID = :NEW.OrderID;

    -- Chọn kho tương ứng: có vận chuyển -> kho gốc (1), không -> kho trực tiếp (2)
    v_warehouse_id := CASE WHEN v_has_shipping = 1 THEN 1 ELSE 2 END;

    -- Lấy tồn kho khả dụng
    SELECT AvailableStock
    INTO v_available
    FROM DetailInventory
    WHERE ProductID = :NEW.ProductID AND WarehouseID = v_warehouse_id;

    IF :NEW.Quantity > v_available THEN
        RAISE_APPLICATION_ERROR(-20001,
            'Số lượng đặt hàng (' || :NEW.Quantity || ') vượt quá tồn kho khả dụng (' || v_available || ').');
    END IF;
EXCEPTION
    WHEN NO_DATA_FOUND THEN
        RAISE_APPLICATION_ERROR(-20002,
            'Không tìm thấy bản ghi tồn kho cho sản phẩm ID=' || :NEW.ProductID || ' tại kho ID=' || v_warehouse_id || '.');
END;

/
ALTER TRIGGER "SGF_ADMIN"."TRG_CHECK_ORDER_QUANTITY" ENABLE;
--------------------------------------------------------
--  DDL for Trigger TRG_CHECK_QC_STATUS
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE TRIGGER "SGF_ADMIN"."TRG_CHECK_QC_STATUS" 
BEFORE INSERT OR UPDATE OF ActionTaken, QC_Status ON ReturnDetail
FOR EACH ROW
BEGIN
    IF :NEW.ActionTaken = 'Nhập lại kho' AND :NEW.QC_Status IS NULL THEN
        RAISE_APPLICATION_ERROR(-20007,
            'Hàng hoàn trả phải được kiểm định (QC_Status) trước khi nhập lại kho.');
    END IF;
END;

