--  DDL for Trigger TRG_CHECK_RETURN_ORDER_STATUS
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE TRIGGER "SGF_ADMIN"."TRG_CHECK_RETURN_ORDER_STATUS" 
BEFORE INSERT ON OrderReturn
FOR EACH ROW
DECLARE
    v_status NUMBER;
BEGIN
    SELECT OrderStatus INTO v_status
    FROM Orders
    WHERE OrderID = :NEW.OrderID;

    IF v_status NOT IN (3, 5) THEN
        RAISE_APPLICATION_ERROR(-20013,
            'Chỉ được hoàn trả đơn hàng đã giao thành công hoặc đã hoàn tất. Trạng thái hiện tại: ' || v_status);
    END IF;
END;

