--  DDL for Trigger TRG_CHECK_UNIQUE_PRODUCT_NAME
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE TRIGGER "SGF_ADMIN"."TRG_CHECK_UNIQUE_PRODUCT_NAME" 
BEFORE INSERT OR UPDATE OF ProductName, CategoryID ON Product
FOR EACH ROW
DECLARE
    v_count NUMBER;
BEGIN
    SELECT COUNT(*)
    INTO v_count
    FROM Product
    WHERE CategoryID = :NEW.CategoryID
      AND ProductName = :NEW.ProductName
      AND ProductID != NVL(:NEW.ProductID, -1);

    IF v_count > 0 THEN
        RAISE_APPLICATION_ERROR(-20010,
            'Tên sản phẩm "' || :NEW.ProductName || '" đã tồn tại trong cùng danh mục.');
    END IF;
END;

